'use client';

import * as React from 'react';
import type { HumationManifest } from '@humation/core';
import { humation1 } from '@humation/assets-humation-1';
import { AvatarColorSheet } from '@/components/humation/color-sheet';
import {
  AvatarPreview,
  type AvatarExportState,
} from '@/components/humation/avatar-preview';
import { AvatarPartPicker } from '@/components/humation/part-picker';
import {
  buildAvatarBuilderModel,
  createAvatarBuilderState,
  randomizeAvatarBuilderState,
} from '@/lib/humation/avatar-state';
import type { HumationAvatarBuilderState } from '@/lib/humation/avatar-state';
import {
  copyAvatarState,
  downloadAvatarPng,
  downloadAvatarSvg,
} from '@/lib/humation/export-avatar';

export type AvatarBuilderProps = {
  assets?: HumationManifest;
  value?: Partial<HumationAvatarBuilderState>;
  defaultValue?: Partial<HumationAvatarBuilderState>;
  seed?: string;
  title?: string;
  filename?: string;
  className?: string;
  hiddenGroupIds?: string[];
  hiddenColorIds?: string[];
  onChange?: (state: HumationAvatarBuilderState) => void;
};

export function AvatarBuilder({
  assets = humation1,
  value,
  defaultValue,
  seed,
  title = 'Humation',
  filename = 'humation-avatar',
  className,
  hiddenGroupIds,
  hiddenColorIds,
  onChange,
}: AvatarBuilderProps) {
  const defaultValueRef = React.useRef(defaultValue);
  const model = React.useMemo(
    () => buildAvatarBuilderModel(assets, { hiddenGroupIds, hiddenColorIds }),
    [assets, hiddenColorIds, hiddenGroupIds]
  );
  const [internalState, setInternalState] =
    React.useState<HumationAvatarBuilderState>(() =>
      createAvatarBuilderState(assets, {
        seed,
        state: defaultValueRef.current,
      })
    );
  const [colorSheetOpen, setColorSheetOpen] = React.useState(false);
  const [exportState, setExportState] =
    React.useState<AvatarExportState>('idle');
  const exportInFlightRef = React.useRef(false);

  React.useEffect(() => {
    setInternalState(
      createAvatarBuilderState(assets, {
        seed,
        state: defaultValueRef.current,
      })
    );
  }, [assets, seed]);

  const state = React.useMemo(
    () =>
      createAvatarBuilderState(assets, {
        seed,
        state: value ?? internalState,
      }),
    [assets, internalState, seed, value]
  );

  const commitState = React.useCallback(
    (nextState: HumationAvatarBuilderState) => {
      if (!value) setInternalState(nextState);
      onChange?.(nextState);
    },
    [onChange, value]
  );

  const handleSelectPart = React.useCallback(
    (slotId: string, partId: string) => {
      commitState({
        ...state,
        selections: { ...state.selections, [slotId]: partId },
      });
    },
    [commitState, state]
  );

  const handleColorChange = React.useCallback(
    (slotId: string, color: string) => {
      commitState({
        ...state,
        colors: { ...state.colors, [slotId]: color },
      });
    },
    [commitState, state]
  );

  const handleBackgroundChange = React.useCallback(
    (background: string) => {
      commitState({ ...state, background });
    },
    [commitState, state]
  );

  const handleRandomize = React.useCallback(() => {
    commitState(randomizeAvatarBuilderState(state, model.groups));
  }, [commitState, model.groups, state]);

  const handleExportPng = React.useCallback(async () => {
    if (exportInFlightRef.current) return;

    exportInFlightRef.current = true;
    setExportState('exporting');
    const startedAt = window.performance.now();
    const finish = (nextState: AvatarExportState) => {
      const delay = Math.max(180 - (window.performance.now() - startedAt), 0);
      window.setTimeout(() => {
        exportInFlightRef.current = false;
        setExportState(nextState);
        window.setTimeout(
          () => setExportState('idle'),
          nextState === 'success' ? 1800 : 2400
        );
      }, delay);
    };

    try {
      await downloadAvatarPng(assets, state, { filename });
      finish('success');
    } catch (error) {
      console.error('Humation PNG export failed:', error);
      finish('error');
    }
  }, [assets, filename, state]);

  const handleDownloadSvg = React.useCallback(() => {
    downloadAvatarSvg(assets, state, { filename });
  }, [assets, filename, state]);

  const handleCopyJson = React.useCallback(async () => {
    await copyAvatarState(state);
  }, [state]);

  return (
    <div
      className={cx(
        'mx-auto flex h-dvh w-full max-w-6xl flex-col overflow-hidden bg-background text-foreground sm:h-auto sm:min-h-[680px] sm:rounded-[2rem] sm:ring-1 sm:ring-border md:grid md:grid-cols-[minmax(280px,0.9fr)_minmax(0,1.1fr)]',
        className
      )}
    >
      <AvatarPreview
        assets={assets}
        state={state}
        title={title}
        exportState={exportState}
        onRandomize={handleRandomize}
        onOpenColors={() => setColorSheetOpen(true)}
        onExportPng={handleExportPng}
        onDownloadSvg={handleDownloadSvg}
        onCopyJson={handleCopyJson}
      />
      <div className="flex min-h-0 flex-1 flex-col">
        <AvatarPartPicker
          assets={assets}
          groups={model.groups}
          state={state}
          onSelectPart={handleSelectPart}
        />
      </div>
      <AvatarColorSheet
        open={colorSheetOpen}
        onOpenChange={setColorSheetOpen}
        colors={model.colors}
        values={state.colors}
        background={state.background}
        onColorChange={handleColorChange}
        onBackgroundChange={handleBackgroundChange}
      />
    </div>
  );
}

function cx(...classes: Array<string | false | null | undefined>) {
  return classes.filter(Boolean).join(' ');
}

'use client';

import { Avatar } from '@humation/react';
import type { HumationManifest } from '@humation/core';
import {
  ArrowDownToLine,
  Check,
  Copy,
  Dice5,
  ImageDown,
  Palette,
  XCircle,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import type { HumationAvatarBuilderState } from '@/lib/humation/avatar-state';
import { toCssColor } from '@/lib/humation/avatar-state';

export type AvatarExportState = 'idle' | 'exporting' | 'success' | 'error';

type AvatarPreviewProps = {
  assets: HumationManifest;
  state: HumationAvatarBuilderState;
  exportState: AvatarExportState;
  title?: string;
  onRandomize: () => void;
  onOpenColors: () => void;
  onExportPng: () => void;
  onDownloadSvg: () => void;
  onCopyJson: () => void;
};

export function AvatarPreview({
  assets,
  state,
  exportState,
  title = 'Humation',
  onRandomize,
  onOpenColors,
  onExportPng,
  onDownloadSvg,
  onCopyJson,
}: AvatarPreviewProps) {
  const exportLabel =
    exportState === 'exporting'
      ? 'Exporting'
      : exportState === 'success'
        ? 'Exported'
        : exportState === 'error'
          ? 'Export failed'
          : 'Export PNG';
  const ExportIcon =
    exportState === 'success'
      ? Check
      : exportState === 'error'
        ? XCircle
        : ImageDown;

  return (
    <section className="flex min-h-[360px] shrink-0 flex-col justify-between gap-5 bg-muted/35 p-4 sm:p-6 md:min-h-[640px] md:p-8">
      <div className="flex items-start justify-between gap-4">
        <div className="min-w-0">
          <h2 className="truncate text-base font-semibold tracking-normal">
            {title}
          </h2>
          <p className="mt-1 text-xs text-muted-foreground">
            {assets.template.name}
          </p>
        </div>
        <Button
          type="button"
          variant="secondary"
          size="icon"
          onClick={onOpenColors}
          aria-label="Edit colors"
          title="Edit colors"
          className="shrink-0 rounded-full"
        >
          <Palette className="size-4" aria-hidden="true" />
        </Button>
      </div>

      <div className="flex flex-1 items-center justify-center">
        <div
          className="relative aspect-square w-full max-w-[320px] overflow-hidden rounded-[2rem] ring-1 ring-border ring-inset md:max-w-[360px]"
          style={{
            background:
              state.background === 'transparent'
                ? 'repeating-conic-gradient(hsl(var(--muted)) 0% 25%, hsl(var(--background)) 0% 50%) 50% / 20px 20px'
                : toCssColor(state.background, assets.defaults.background),
          }}
        >
          <Avatar
            assets={assets}
            selections={state.selections}
            colors={state.colors}
            background="transparent"
            crop={state.crop}
            title={`${title} preview`}
            className="h-full w-full"
          />
        </div>
      </div>

      <div className="grid grid-cols-2 gap-2 sm:grid-cols-4 md:grid-cols-2 lg:grid-cols-4">
        <Button type="button" variant="outline" onClick={onRandomize}>
          <Dice5 className="mr-2 size-4" aria-hidden="true" />
          Random
        </Button>
        <Button
          type="button"
          onClick={onExportPng}
          disabled={exportState === 'exporting'}
          variant={exportState === 'error' ? 'destructive' : 'default'}
        >
          <ExportIcon
            className={cx(
              'mr-2 size-4',
              exportState === 'exporting' && 'animate-pulse'
            )}
            aria-hidden="true"
          />
          {exportLabel}
        </Button>
        <Button type="button" variant="secondary" onClick={onDownloadSvg}>
          <ArrowDownToLine className="mr-2 size-4" aria-hidden="true" />
          SVG
        </Button>
        <Button type="button" variant="secondary" onClick={onCopyJson}>
          <Copy className="mr-2 size-4" aria-hidden="true" />
          JSON
        </Button>
      </div>
    </section>
  );
}

function cx(...classes: Array<string | false | null | undefined>) {
  return classes.filter(Boolean).join(' ');
}

'use client';

import * as React from 'react';
import type { HumationManifest, PartOption } from '@humation/core';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import type {
  HumationAvatarBuilderState,
  HumationPartGroup,
  HumationPartSubgroup,
} from '@/lib/humation/avatar-state';
import {
  formatPartLabel,
  getPartPreviewDataUri,
} from '@/lib/humation/avatar-state';

type AvatarPartPickerProps = {
  assets: HumationManifest;
  groups: HumationPartGroup[];
  state: HumationAvatarBuilderState;
  onSelectPart: (slotId: string, partId: string) => void;
};

export function AvatarPartPicker({
  assets,
  groups,
  state,
  onSelectPart,
}: AvatarPartPickerProps) {
  const defaultTab = groups[0]?.id ?? '';
  const [activeTab, setActiveTab] = React.useState(defaultTab);

  React.useEffect(() => {
    if (!groups.some((group) => group.id === activeTab)) {
      setActiveTab(defaultTab);
    }
  }, [activeTab, defaultTab, groups]);

  if (groups.length === 0) return null;

  return (
    <Tabs
      value={activeTab}
      onValueChange={setActiveTab}
      className="flex min-h-0 flex-1 flex-col"
    >
      <div className="shrink-0 border-b px-3 pt-3 md:px-5 md:pt-5">
        <TabsList className="h-10 w-full justify-start overflow-x-auto rounded-none bg-transparent p-0">
          {groups.map((group) => (
            <TabsTrigger
              key={group.id}
              value={group.id}
              className="h-10 rounded-none border-b-2 border-transparent px-3 text-sm data-[state=active]:border-primary data-[state=active]:bg-transparent data-[state=active]:shadow-none"
            >
              {group.label}
            </TabsTrigger>
          ))}
        </TabsList>
      </div>

      <ScrollArea className="min-h-0 flex-1">
        <div className="px-3 py-4 md:px-5">
          {groups.map((group) => (
            <TabsContent key={group.id} value={group.id} className="m-0">
              <PartGroupPanel
                assets={assets}
                group={group}
                state={state}
                onSelectPart={onSelectPart}
              />
            </TabsContent>
          ))}
        </div>
      </ScrollArea>
    </Tabs>
  );
}

function PartGroupPanel({
  assets,
  group,
  state,
  onSelectPart,
}: {
  assets: HumationManifest;
  group: HumationPartGroup;
  state: HumationAvatarBuilderState;
  onSelectPart: (slotId: string, partId: string) => void;
}) {
  const [subgroupId, setSubgroupId] = React.useState(
    group.subgroups[0]?.id ?? group.id
  );
  const selectedSubgroup =
    group.subgroups.find((subgroup) => subgroup.id === subgroupId) ??
    group.subgroups[0];

  React.useEffect(() => {
    if (!group.subgroups.some((subgroup) => subgroup.id === subgroupId)) {
      setSubgroupId(group.subgroups[0]?.id ?? group.id);
    }
  }, [group, subgroupId]);

  return (
    <div className="flex flex-col gap-3">
      {group.subgroups.length > 1 ? (
        <div className="flex gap-2 overflow-x-auto pb-1">
          {group.subgroups.map((subgroup) => (
            <button
              key={subgroup.id}
              type="button"
              onClick={() => setSubgroupId(subgroup.id)}
              className={cx(
                'h-8 shrink-0 rounded-full px-3 text-xs font-medium transition-colors',
                subgroupId === subgroup.id
                  ? 'bg-primary text-primary-foreground'
                  : 'bg-muted text-muted-foreground hover:text-foreground'
              )}
            >
              {subgroup.label}
            </button>
          ))}
        </div>
      ) : null}

      {selectedSubgroup ? (
        <PartGrid
          assets={assets}
          subgroup={selectedSubgroup}
          state={state}
          onSelectPart={onSelectPart}
        />
      ) : null}
    </div>
  );
}

function PartGrid({
  assets,
  subgroup,
  state,
  onSelectPart,
}: {
  assets: HumationManifest;
  subgroup: HumationPartSubgroup;
  state: HumationAvatarBuilderState;
  onSelectPart: (slotId: string, partId: string) => void;
}) {
  return (
    <div className="grid grid-cols-3 gap-2 sm:grid-cols-4 lg:grid-cols-5">
      {subgroup.parts.map((part) => (
        <PartButton
          key={part.id}
          assets={assets}
          part={part}
          subgroup={subgroup}
          state={state}
          onSelectPart={onSelectPart}
        />
      ))}
    </div>
  );
}

function PartButton({
  assets,
  part,
  subgroup,
  state,
  onSelectPart,
}: {
  assets: HumationManifest;
  part: PartOption;
  subgroup: HumationPartSubgroup;
  state: HumationAvatarBuilderState;
  onSelectPart: (slotId: string, partId: string) => void;
}) {
  const selected = state.selections[subgroup.selectionSlot] === part.id;
  const label = formatPartLabel(part);

  return (
    <button
      type="button"
      title={label}
      aria-label={`${subgroup.label}: ${label}`}
      aria-pressed={selected}
      data-part-id={part.id}
      data-source-part-id={part.source?.partId}
      onClick={() => onSelectPart(subgroup.selectionSlot, part.id)}
      className={cx(
        'relative flex aspect-square min-w-0 items-center justify-center overflow-hidden rounded-2xl bg-background p-3 ring-1 ring-border ring-inset transition active:scale-[0.98]',
        selected
          ? 'bg-accent ring-2 ring-primary'
          : 'hover:bg-accent/60 hover:ring-ring'
      )}
    >
      {/* eslint-disable-next-line @next/next/no-img-element */}
      <img
        src={getPartPreviewDataUri(assets, part, state)}
        alt=""
        className={cx(
          'max-h-full max-w-full select-none',
          subgroup.selectionSlot === 'glasses' && 'scale-[2.15]'
        )}
        draggable={false}
      />
    </button>
  );
}

function cx(...classes: Array<string | false | null | undefined>) {
  return classes.filter(Boolean).join(' ');
}

'use client';

import * as React from 'react';
import type { ColorSlot } from '@humation/core';
import { X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
  Sheet,
  SheetClose,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from '@/components/ui/sheet';
import {
  formatColorLabel,
  normalizeHexColor,
  toCssColor,
} from '@/lib/humation/avatar-state';

type AvatarColorSheetProps = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  colors: ColorSlot[];
  values: Record<string, string>;
  background: string;
  onColorChange: (slotId: string, color: string) => void;
  onBackgroundChange: (color: string) => void;
};

export function AvatarColorSheet({
  open,
  onOpenChange,
  colors,
  values,
  background,
  onColorChange,
  onBackgroundChange,
}: AvatarColorSheetProps) {
  const backgroundSlot = colors.find((color) => color.id === 'background');
  const colorSlots = colors.filter((color) => color.id !== 'background');

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        className="mx-auto max-h-[78dvh] rounded-t-[2rem] px-0 pb-0 sm:max-w-xl"
      >
        <SheetHeader className="flex flex-row items-center justify-between gap-3 px-4 pb-2 pt-4 text-left">
          <SheetTitle className="text-base">Colors</SheetTitle>
          <SheetClose asChild>
            <Button
              type="button"
              variant="secondary"
              size="icon"
              aria-label="Close colors"
              className="rounded-full"
            >
              <X className="size-4" aria-hidden="true" />
            </Button>
          </SheetClose>
        </SheetHeader>

        <div className="flex flex-col gap-1 overflow-y-auto px-4 pb-5">
          {colorSlots.map((color) => (
            <ColorRow
              key={color.id}
              label={formatColorLabel(color)}
              hexColor={values[color.id] ?? color.default}
              fallback={color.default}
              onChange={(nextColor) => onColorChange(color.id, nextColor)}
            />
          ))}

          {backgroundSlot ? (
            <ColorRow
              label={formatColorLabel(backgroundSlot)}
              hexColor={
                background === 'transparent'
                  ? backgroundSlot.default
                  : background
              }
              fallback={backgroundSlot.default}
              onChange={onBackgroundChange}
              trailing={
                backgroundSlot.allowTransparent ? (
                  <Button
                    type="button"
                    variant={
                      background === 'transparent' ? 'default' : 'secondary'
                    }
                    size="sm"
                    onClick={() =>
                      onBackgroundChange(
                        background === 'transparent'
                          ? backgroundSlot.default
                          : 'transparent'
                      )
                    }
                  >
                    Transparent
                  </Button>
                ) : null
              }
            />
          ) : null}
        </div>
      </SheetContent>
    </Sheet>
  );
}

type ColorRowProps = {
  label: string;
  hexColor: string;
  fallback: string;
  onChange: (color: string) => void;
  trailing?: React.ReactNode;
};

function ColorRow({
  label,
  hexColor,
  fallback,
  onChange,
  trailing,
}: ColorRowProps) {
  const [localColor, setLocalColor] = React.useState(
    `#${normalizeHexColor(hexColor, fallback)}`
  );
  const timeoutRef = React.useRef<ReturnType<typeof setTimeout> | null>(null);
  const onChangeRef = React.useRef(onChange);

  onChangeRef.current = onChange;

  React.useEffect(() => {
    if (hexColor === 'transparent') return;
    setLocalColor(`#${normalizeHexColor(hexColor, fallback)}`);
  }, [fallback, hexColor]);

  React.useEffect(() => {
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
    };
  }, []);

  const commitColor = React.useCallback((value: string) => {
    onChangeRef.current(value.replace('#', '').toUpperCase());
  }, []);

  const handleInput = React.useCallback(
    (event: React.FormEvent<HTMLInputElement>) => {
      const value = event.currentTarget.value;
      setLocalColor(value);

      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      timeoutRef.current = setTimeout(() => commitColor(value), 240);
    },
    [commitColor]
  );

  const handleChange = React.useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      const value = event.currentTarget.value;
      setLocalColor(value);

      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      commitColor(value);
    },
    [commitColor]
  );

  return (
    <label className="flex min-h-14 cursor-pointer items-center justify-between gap-4 rounded-xl px-2 py-2 transition-colors hover:bg-muted/55">
      <span className="min-w-0 truncate text-sm font-medium">{label}</span>
      <span className="flex shrink-0 items-center gap-3">
        <span className="font-mono text-xs tabular-nums text-muted-foreground">
          {localColor.toUpperCase()}
        </span>
        {trailing}
        <span className="relative h-10 w-10 shrink-0 overflow-hidden rounded-full bg-background ring-1 ring-border ring-inset transition-shadow focus-within:ring-2 focus-within:ring-primary">
          <span
            aria-hidden="true"
            className="absolute inset-1 rounded-full"
            style={{ background: toCssColor(localColor, fallback) }}
          />
          <input
            type="color"
            value={localColor}
            onInput={handleInput}
            onChange={handleChange}
            aria-label={label}
            className="absolute inset-0 h-full w-full cursor-pointer opacity-0"
          />
        </span>
      </span>
    </label>
  );
}

import {
  createAvatar,
  createPartPreview,
  getPartsForUiGroup,
} from '@humation/core';
import type {
  ColorSlot,
  CreateAvatarOptions,
  HumationManifest,
  PartOption,
  UiGroup,
} from '@humation/core';

export type HumationAvatarBuilderState = {
  selections: Record<string, string>;
  colors: Record<string, string>;
  background: string;
  crop?: CreateAvatarOptions['crop'];
};

export type HumationPartSubgroup = {
  id: string;
  label: string;
  selectionSlot: string;
  sourceGroupId: string;
  defaultPart: string;
  order: number;
  parts: PartOption[];
};

export type HumationPartGroup = {
  id: string;
  label: string;
  selectionSlot: string;
  defaultPart: string;
  order: number;
  parts: PartOption[];
  subgroups: HumationPartSubgroup[];
};

export type HumationAvatarBuilderModel = {
  groups: HumationPartGroup[];
  colors: ColorSlot[];
};

export type CreateBuilderStateOptions = {
  seed?: string;
  state?: Partial<HumationAvatarBuilderState>;
};

const DEFAULT_HIDDEN_GROUP_IDS = new Set(['bottom']);
const DEFAULT_HIDDEN_COLOR_IDS = new Set(['bottom']);
const PREFERRED_GROUP_ORDER = ['head', 'body', 'item', 'glasses'];

export function createAvatarBuilderState(
  manifest: HumationManifest,
  options: CreateBuilderStateOptions = {}
): HumationAvatarBuilderState {
  const seededSelections = options.seed
    ? createAvatar(manifest, { seed: options.seed }).toJSON().selections
    : {};

  return {
    selections: {
      ...manifest.defaults.selections,
      ...seededSelections,
      ...(options.state?.selections ?? {}),
    },
    colors: {
      ...manifest.defaults.colors,
      ...(options.state?.colors ?? {}),
    },
    background: options.state?.background ?? manifest.defaults.background,
    crop: options.state?.crop ?? manifest.defaults.crop,
  };
}

export function buildAvatarBuilderModel(
  manifest: HumationManifest,
  options: {
    hiddenGroupIds?: string[];
    hiddenColorIds?: string[];
  } = {}
): HumationAvatarBuilderModel {
  const hiddenGroupIds = new Set([
    ...DEFAULT_HIDDEN_GROUP_IDS,
    ...(options.hiddenGroupIds ?? []),
  ]);
  const hiddenColorIds = new Set([
    ...DEFAULT_HIDDEN_COLOR_IDS,
    ...(options.hiddenColorIds ?? []),
  ]);
  const bySelectionSlot = new Map<string, HumationPartGroup>();

  for (const uiGroup of manifest.uiGroups) {
    if (isHidden(uiGroup.id, uiGroup.label, hiddenGroupIds)) continue;

    const subgroup = buildSubgroup(manifest, uiGroup);
    if (!subgroup || subgroup.parts.length === 0) continue;

    const slot = manifest.selectionSlots.find(
      (candidate) => candidate.id === subgroup.selectionSlot
    );
    const existing = bySelectionSlot.get(subgroup.selectionSlot);

    if (existing) {
      existing.subgroups.push(subgroup);
      existing.parts = mergeUniqueParts(existing.parts, subgroup.parts);
      existing.order = Math.min(existing.order, subgroup.order);
      continue;
    }

    bySelectionSlot.set(subgroup.selectionSlot, {
      id: subgroup.selectionSlot,
      label: slot?.label ?? subgroup.label,
      selectionSlot: subgroup.selectionSlot,
      defaultPart: subgroup.defaultPart,
      order: subgroup.order,
      parts: subgroup.parts,
      subgroups: [subgroup],
    });
  }

  const groups = [...bySelectionSlot.values()].sort(sortBuilderGroups);
  for (const group of groups) {
    group.subgroups.sort((left, right) => left.order - right.order);
  }

  return {
    groups,
    colors: manifest.colors.filter(
      (color) => !isHidden(color.id, color.label, hiddenColorIds)
    ),
  };
}

export function randomizeAvatarBuilderState(
  state: HumationAvatarBuilderState,
  groups: HumationPartGroup[]
): HumationAvatarBuilderState {
  const selections = { ...state.selections };

  for (const group of groups) {
    const parts = group.parts.filter((part) => !part.deprecated);
    if (parts.length === 0) continue;
    selections[group.selectionSlot] =
      parts[Math.floor(Math.random() * parts.length)].id;
  }

  return { ...state, selections };
}

export function getPartPreviewDataUri(
  manifest: HumationManifest,
  part: PartOption,
  state: HumationAvatarBuilderState
) {
  return createPartPreview(manifest, part, {
    colors: state.colors,
    background: 'transparent',
  }).toDataUri();
}

export function formatPartLabel(part: PartOption) {
  return titleCase(part.name ?? part.source?.partId ?? part.id);
}

export function formatColorLabel(color: ColorSlot) {
  if (color.id === 'clothes') return 'Cloth';
  return color.label;
}

export function normalizeHexColor(color: string, fallback = '000000') {
  const normalized = color.replace('#', '').trim().toUpperCase();
  return /^[0-9A-F]{6}$/.test(normalized)
    ? normalized
    : fallback.replace('#', '').trim().toUpperCase();
}

export function toCssColor(color: string, fallback = '000000') {
  if (color === 'transparent') return 'transparent';
  return `#${normalizeHexColor(color, fallback)}`;
}

function buildSubgroup(
  manifest: HumationManifest,
  uiGroup: UiGroup
): HumationPartSubgroup | undefined {
  const selectionSlot = uiGroup.selectionSlots[0] ?? uiGroup.id;
  const defaultPart =
    manifest.defaults.selections[selectionSlot] ??
    manifest.selectionSlots.find((slot) => slot.id === selectionSlot)
      ?.defaultPart ??
    '';

  const parts = getGroupParts(manifest, uiGroup, selectionSlot, defaultPart);

  return {
    id: uiGroup.id,
    label: uiGroup.label,
    selectionSlot,
    sourceGroupId: uiGroup.id,
    defaultPart,
    order: uiGroup.order,
    parts,
  };
}

function getGroupParts(
  manifest: HumationManifest,
  uiGroup: UiGroup,
  selectionSlot: string,
  defaultPart: string
) {
  const selectionSlots = new Set(uiGroup.selectionSlots);
  const allowedPartIds = uiGroup.partIds ? new Set(uiGroup.partIds) : undefined;
  const parts = getPartsForUiGroup(manifest, uiGroup.id).filter((part) => {
    if (!selectionSlots.has(part.selectionSlot)) return false;
    if (allowedPartIds && !allowedPartIds.has(part.id)) return false;
    return true;
  });

  if (selectionSlot !== 'item') return parts;

  return [...parts].sort((left, right) => {
    if (left.id === defaultPart) return -1;
    if (right.id === defaultPart) return 1;

    const leftNumber = Number(left.source?.partId);
    const rightNumber = Number(right.source?.partId);

    if (Number.isFinite(leftNumber) && Number.isFinite(rightNumber)) {
      return rightNumber - leftNumber;
    }

    return right.id.localeCompare(left.id);
  });
}

function sortBuilderGroups(left: HumationPartGroup, right: HumationPartGroup) {
  const leftPreferred = PREFERRED_GROUP_ORDER.indexOf(left.selectionSlot);
  const rightPreferred = PREFERRED_GROUP_ORDER.indexOf(right.selectionSlot);
  const leftRank =
    leftPreferred === -1 ? Number.MAX_SAFE_INTEGER : leftPreferred;
  const rightRank =
    rightPreferred === -1 ? Number.MAX_SAFE_INTEGER : rightPreferred;

  return leftRank - rightRank || left.order - right.order;
}

function mergeUniqueParts(left: PartOption[], right: PartOption[]) {
  const seen = new Set(left.map((part) => part.id));
  const merged = [...left];

  for (const part of right) {
    if (seen.has(part.id)) continue;
    seen.add(part.id);
    merged.push(part);
  }

  return merged;
}

function isHidden(id: string, label: string, hidden: Set<string>) {
  return hidden.has(id) || hidden.has(label.toLowerCase());
}

function titleCase(value: string) {
  return value
    .replace(/[-_]+/g, ' ')
    .replace(/\b\w/g, (letter) => letter.toUpperCase());
}

import { createAvatar } from '@humation/core';
import type { HumationManifest } from '@humation/core';
import type { HumationAvatarBuilderState } from '@/lib/humation/avatar-state';

export type AvatarExportOptions = {
  filename?: string;
  pngSize?: number;
};

export function renderAvatarSvg(
  manifest: HumationManifest,
  state: HumationAvatarBuilderState
) {
  return createAvatar(manifest, {
    selections: state.selections,
    colors: state.colors,
    background: state.background,
    crop: state.crop,
  }).toString();
}

export function serializeAvatarState(state: HumationAvatarBuilderState) {
  return JSON.stringify(
    {
      selections: state.selections,
      colors: state.colors,
      background: state.background,
      crop: state.crop,
    },
    null,
    2
  );
}

export async function copyAvatarState(state: HumationAvatarBuilderState) {
  await navigator.clipboard.writeText(serializeAvatarState(state));
}

export function downloadAvatarSvg(
  manifest: HumationManifest,
  state: HumationAvatarBuilderState,
  options: AvatarExportOptions = {}
) {
  const svg = renderAvatarSvg(manifest, state);
  const blob = new Blob([svg], { type: 'image/svg+xml;charset=utf-8' });
  downloadBlob(blob, buildFilename(options.filename, 'svg'));
}

export async function downloadAvatarPng(
  manifest: HumationManifest,
  state: HumationAvatarBuilderState,
  options: AvatarExportOptions = {}
) {
  const svg = renderAvatarSvg(manifest, state);
  const blob = await svgToPngBlob(svg, options.pngSize ?? 1024);
  downloadBlob(blob, buildFilename(options.filename, 'png'));
}

export async function svgToPngBlob(svg: string, targetSize: number) {
  const image = new Image();
  image.decoding = 'async';
  image.src = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`;

  await new Promise<void>((resolve, reject) => {
    image.onload = () => resolve();
    image.onerror = () =>
      reject(new Error('Failed to load SVG as image for PNG export'));
  });

  const width = image.naturalWidth || image.width || targetSize;
  const height = image.naturalHeight || image.height || targetSize;
  const scale = targetSize / Math.max(width, height);
  const canvas = document.createElement('canvas');
  canvas.width = Math.max(1, Math.round(width * scale));
  canvas.height = Math.max(1, Math.round(height * scale));

  const context = canvas.getContext('2d');
  if (!context) throw new Error('Canvas context is not available');

  context.drawImage(image, 0, 0, canvas.width, canvas.height);

  return new Promise<Blob>((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (blob) resolve(blob);
      else reject(new Error('Canvas toBlob returned null'));
    }, 'image/png');
  });
}

function downloadBlob(blob: Blob, filename: string) {
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = url;
  anchor.download = filename;
  document.body.appendChild(anchor);
  anchor.click();
  document.body.removeChild(anchor);
  window.setTimeout(() => URL.revokeObjectURL(url), 5000);
}

function buildFilename(filename: string | undefined, extension: string) {
  const base = (filename ?? 'humation-avatar')
    .trim()
    .replace(/\.[a-z0-9]+$/i, '')
    .replace(/[^a-z0-9-_]+/gi, '-')
    .replace(/^-+|-+$/g, '')
    .toLowerCase();

  return `${base || 'humation-avatar'}.${extension}`;
}
